import logging
from django.http import Http404
from rest_framework.exceptions import ValidationError
import requests
from requests.exceptions import Timeout, ConnectionError

logger = logging.getLogger(__name__)

# Good: Specific exceptions
def get_user_or_404(user_id: int) -> User:
    try:
        return User.objects.get(pk=user_id)
    except User.DoesNotExist:
        raise Http404(f"User {user_id} not found")

# Good: Multiple specific exceptions
def fetch_external_data(url: str) -> dict:
    try:
        response = requests.get(url, timeout=30)
        response.raise_for_status()
        return response.json()
    except Timeout:
        logger.warning("Request to %s timed out", url)
        raise ExternalServiceError("Timeout")
    except ConnectionError:
        logger.error("Connection failed to %s", url, exc_info=True)
        raise ExternalServiceError("Cannot connect")

from django.db.models import QuerySet
from typing import Optional

# Good: Full type hints
def get_active_orders(user: User) -> QuerySet[Order]:
    """Fetch all active orders for a user."""
    return Order.objects.filter(
        user=user,
        status__in=["pending", "processing"]
    )

# Good: Optional return
def get_user_or_none(user_id: int) -> Optional[User]:
    """Get user or return None if not found."""
    return User.objects.filter(pk=user_id).first()

