# checks.py
from django.core.checks import Error, Warning, register

@register(Tags.security, deploy=True)
def check_secret_key_not_default(app_configs, **kwargs):
    """Ensure SECRET_KEY is not the default insecure value."""
    from django.conf import settings

    errors = []
    if settings.SECRET_KEY == "django-insecure-change-me":
        errors.append(
            Error(
                "SECRET_KEY is set to an insecure default.",
                hint="Generate new SECRET_KEY with: python -c 'from django.core.management.utils import get_random_secret_key; print(get_random_secret_key())'",
                id="security.E001",
            )
        )
    return errors

# apps.py
class MyAppConfig(AppConfig):
    name = "myapp"

    def ready(self):
        from . import checks  # noqa: F401  - register checks
